// JSX you write
const element = (
  <div className="card" key="item-1">
    <h1>Hello</h1>
    <p style={{ color: 'red' }}>Count: 0</p>
  </div>
);

// Babel compiles to (React 17+ automatic runtime):
import { jsx as _jsx, jsxs as _jsxs } from 'react/jsx-runtime';
const element = _jsxs('div', {
  className: 'card',
  children: [
    _jsx('h1', { children: 'Hello' }),
    _jsx('p', { style: { color: 'red' }, children: 'Count: 0' }),
  ],
}, 'item-1');

// The plain object returned:
// {
//   $$typeof: Symbol(react.element),  // XSS guard
//   type:     'div',
//   key:      'item-1',
//   ref:      null,
//   props: {
//     className: 'card',
//     children: [ <h1 element>, <p element> ],
//   },
// }

function Counter({ initialCount }) {
  const [count, setCount] = useState(initialCount);

  // This function body IS the render phase for this component.
  // React may call it multiple times (StrictMode, suspense, etc.)
  // without any guarantee of DOM access — keep it pure.
  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={() => setCount(c => c + 1)}>+</button>
    </div>
  );
}

// Without keys — positional match
// Prepending 'Alpha' forces React to update EVERY item
['Alpha', 'Beta', 'Gamma'].map(item => <li>{item}</li>)
// React sees: item 0 changed from 'Beta' to 'Alpha', item 1 changed, etc.

// With keys — identity match
['Alpha', 'Beta', 'Gamma'].map(item => <li key={item}>{item}</li>)
// React sees: new key 'Alpha' inserted at position 0; 'Beta' and 'Gamma'
// have stable keys — they are moved/updated with no text change.

function Parent() {
  const [count, setCount] = useState(0);

  return (
    <div>
      {/* StaticChild re-renders on every Parent state change... */}
      <StaticChild label="unchanged" />
      {/* ...but its DOM node is never touched — label prop didn't change */}
      <p>Count: {count}</p>
    </div>
  );
}

// Wrap StaticChild in React.memo to skip even the re-render
const StaticChild = React.memo(function StaticChild({ label }) {
  return <span>{label}</span>;
});

import { Profiler } from 'react';

function onRenderCallback(id, phase, actualDuration) {
  console.log(`${id} (${phase}): ${actualDuration.toFixed(2)}ms`);
}

function App() {
  return (
    <Profiler id="Dashboard" onRender={onRenderCallback}>
      <Dashboard />
    </Profiler>
  );
}
// actualDuration = time spent rendering component and descendants
// phase: 'mount' | 'update'

// This is correct — create a new element with updated props
function App() {
  const [count, setCount] = useState(0);
  // A new element is created on every render; React diffs it against the previous one
  return <p>Count: {count}</p>;
}

// This is wrong — mutating an element after creation
const el = <p>Hello</p>;
el.props.children = 'World'; // TypeError in development (props is frozen)
                              // Silent corruption in production

// Component (a factory)
function Button({ label, onClick }) {
  return <button onClick={onClick}>{label}</button>;
}

// Element (a description of what to render)
const el = <Button label="Click me" onClick={handleClick} />;
// el is the object: { type: Button, props: { label: 'Click me', onClick: fn } }
// React calls Button(el.props) to get the next level: { type: 'button', props: {...} }
// This continues recursively until only host elements (strings) remain.

import { createPortal } from 'react-dom';

function Modal({ children, onClose }) {
  // Renders children into document.body instead of the nearest DOM parent...
  return createPortal(
    <div className="modal-overlay" onClick={onClose}>
      {children}
    </div>,
    document.body
  );
}

function App() {
  const [open, setOpen] = useState(false);
  return (
    <div className="app">
      <button onClick={() => setOpen(true)}>Open Modal</button>
      {open && (
        // ...but in React's tree, Modal is a child of <div.app>
        // Click events inside Modal still bubble to <div.app> handlers
        <Modal onClose={() => setOpen(false)}>
          <p>Hello from a portal!</p>
        </Modal>
      )}
    </div>
  );
}

// server.js (Next.js or Remix handles this for you)
import { renderToString } from 'react-dom/server';
const html = renderToString(<App />);
// Returns: <div class="app"><p>Count: 0</p></div>

// client.js — attach React to server HTML
import { hydrateRoot } from 'react-dom/client';
hydrateRoot(document.getElementById('root'), <App />);
// React walks the existing DOM, attaches event listeners,
// and builds an internal Fiber tree matching the HTML.
// No DOM writes happen if the HTML matches.

import { startTransition, useTransition } from 'react';

function SearchResults({ query }) {
  const [results, setResults] = useState([]);
  const [isPending, startTransition] = useTransition();

  function handleSearch(e) {
    const q = e.target.value;
    startTransition(() => {
      // This setState is low-priority — React may interrupt its render
      // if a higher-priority update (another keystroke) arrives
      setResults(computeExpensiveResults(q));
    });
  }

  return (
    <>
      <input onChange={handleSearch} />
      {isPending ? <p>Loading…</p> : <ResultList items={results} />}
    </>
  );
}

// Bad: index as key when items can be reordered
todos.map((todo, index) => <TodoItem key={index} todo={todo} />)

// Bad: random key — forces full remount every render
todos.map(todo => <TodoItem key={Math.random()} todo={todo} />)

// Good: stable identity-based key
todos.map(todo => <TodoItem key={todo.id} todo={todo} />)

