  const [count, setCount] = useState(0);
  return (
    <div>
      <ExpensiveChild /> {/* re-renders on every count change */}
      <p>{count}</p>
    </div>
  );
}

// Fix: memoize ExpensiveChild so it only re-renders when its own props change
const ExpensiveChild = React.memo(function ExpensiveChild() {
  // Expensive calculation here
  return <div>{/* ... */}</div>;
});

import { FixedSizeList } from 'react-window';

function VirtualisedList({ items }) {
  const Row = ({ index, style }) => (
    <div style={style}>{items[index].name}</div>
  );

  return (
    <FixedSizeList
      height={600}        // visible container height
      itemCount={items.length}
      itemSize={35}       // each row height in px
      width="100%"
    >
      {Row}
    </FixedSizeList>
  );
}
// With 10 000 items, only ~17 rows exist in the DOM at once.
